#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 100005
#define MAXM 100005

long long fib[MAXN];

void precompute_fib() {
    fib[1] = 1;
    fib[2] = 1;
    for (int i = 3; i < MAXN; i++) {
        fib[i] = (fib[i-1] + fib[i-2]) % MOD;
    }
}

long long calculate_f(int* arr, int l, int r) {
    long long res = 0;
    int n = r - l + 1;
    for (int mask = 0; mask < (1 << n); mask++) {
        long long sum = 0;
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                sum = (sum + arr[l + i]) % MOD;
            }
        }
        res = (res + fib[sum]) % MOD;
    }
    return res;
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int* arr = (int*) malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    precompute_fib();
    for (int i = 0; i < m; i++) {
        char type;
        scanf(" %c", &type);
        if (type == 'C') {
            int x, y;
            scanf("%d %d", &x, &y);
            arr[x-1] = y;
        } else {
            int l, r;
            scanf("%d %d", &l, &r);
            printf("%lld\n", calculate_f(arr, l-1, r-1));
        }
    }
    free(arr);
    return 0;
}

