import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    static final int MAXN = 100005;
    static final int MAXM = 100005;
    static long[] fib = new long[MAXN];

    public static void precompute_fib() {
        fib[1] = 1;
        fib[2] = 1;
        for (int i = 3; i < MAXN; i++) {
            fib[i] = (fib[i-1] + fib[i-2]) % MOD;
        }
    }

    public static long calculate_f(int[] arr, int l, int r) {
        long res = 0;
        int n = r - l + 1;
        for (int mask = 0; mask < (1 << n); mask++) {
            long sum = 0;
            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) != 0) {
                    sum = (sum + arr[l + i]) % MOD;
                }
            }
            res = (res + fib[(int) sum]) % MOD;
        }
        return res;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int m = scanner.nextInt();
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) {
            arr[i] = scanner.nextInt();
        }
        precompute_fib();
        for (int i = 0; i < m; i++) {
            char type = scanner.next().charAt(0);
            if (type == 'C') {
                int x = scanner.nextInt();
                int y = scanner.nextInt();
                arr[x-1] = y;
            } else {
                int l = scanner.nextInt();
                int r = scanner.nextInt();
                System.out.println(calculate_f(arr, l-1, r-1));
            }
        }
    }
}

